+async function supportsFinePointer(page: Page) {
+  return page.evaluate(
+    () =>
+      typeof window !== "undefined" &&
+      window.matchMedia("(hover: hover) and (pointer: fine)").matches
+  );
+}
+
+async function isToolCardInViewport(page: Page, toolId: string) {
+  return page.evaluate((id) => {
+    const toolCard = document.getElementById(`tool-card-${id}`);
+    const card = toolCard?.querySelector("[data-testid='tool-card']") ?? toolCard;
+
+    if (!card) {
+      return false;
+    }
+
+    const rect = card.getBoundingClientRect();
+    return (
+      rect.width > 0 &&
+      rect.height > 0 &&
+      rect.top < window.innerHeight &&
+      rect.bottom > 0 &&
+      rect.left < window.innerWidth &&
+      rect.right > 0
+    );
+  }, toolId);
+}
+
+async function waitForToolCardNavigation(page: Page, toolId: string, initialScroll: number) {
+  return expect
+    .poll(
+      async () => {
+        const visible = await isToolCardInViewport(page, toolId);
+        if (visible) {
+          return true;
+        }
+
+        const currentScroll = await page.evaluate(() => window.scrollY);
+        return Math.abs(currentScroll - initialScroll) > 20;
+      },
+      { timeout: 6000, intervals: [50, 100, 150, 250, 500] }
+    )
+    .toBe(true);
+}
+
+async function blurActiveElement(page: Page) {
+  await page.evaluate(() => {
+    const activeElement = document.activeElement as Element | null;
+    activeElement?.blur?.();
+  });
+}
+
+async function isToolCardHighlighted(page: Page, toolId: string) {
+  const selector = `#tool-card-${toolId} [data-testid="tool-card"], #tool-card-${toolId}`;
+
+  return page.$$eval(selector, (els) =>
+    els.some((el) => el.getAttribute("data-diagram-highlighted") === "true")
+  );
+}
